import{_ as o,o as t,c as a,ag as r}from"./chunks/framework.B_-t2C-M.js";const g=JSON.parse('{"title":"Architecture & Models","description":"","frontmatter":{},"headers":[],"relativePath":"guide/architecture.md","filePath":"guide/architecture.md"}'),i={name:"guide/architecture.md"};function s(n,e,c,d,l,u){return t(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="architecture-models" tabindex="-1">Architecture &amp; Models <a class="header-anchor" href="#architecture-models" aria-label="Permalink to &quot;Architecture &amp; Models&quot;">​</a></h1><p>LaraCommerce is designed using a modular, domain-driven approach within the Laravel ecosystem. The database consists of over <strong>80 Eloquent Models</strong> and <strong>72 Migrations</strong>, covering every aspect of a modern ecommerce platform.</p><hr><h2 id="core-domains" tabindex="-1">Core Domains <a class="header-anchor" href="#core-domains" aria-label="Permalink to &quot;Core Domains&quot;">​</a></h2><p>The application is structured around several key domains, each managed by its own set of models and services.</p><h3 id="_1-catalog-products" tabindex="-1">1. Catalog &amp; Products <a class="header-anchor" href="#_1-catalog-products" aria-label="Permalink to &quot;1. Catalog &amp; Products&quot;">​</a></h3><p>The core of the store, supporting complex product structures.</p><ul><li><strong><code>Product</code></strong>: The base item. Supports soft deletes, scouting (Meilisearch), and tracks view/sold counts.</li><li><strong><code>ProductVariant</code></strong>: Handles physical inventory, specific SKUs, pricing, and stock levels. A product can have one or many variants.</li><li><strong><code>Attribute</code> &amp; <code>AttributeValue</code></strong>: Dynamic properties (e.g., Size = Large, Color = Red).</li><li><strong><code>Category</code> &amp; <code>Brand</code></strong>: Hierarchical classification and manufacturer grouping.</li><li><strong><code>ProductImage</code> &amp; <code>ProductTranslation</code></strong>: Multi-media and multi-lingual support.</li></ul><h3 id="_2-orders-checkout" tabindex="-1">2. Orders &amp; Checkout <a class="header-anchor" href="#_2-orders-checkout" aria-label="Permalink to &quot;2. Orders &amp; Checkout&quot;">​</a></h3><p>Handles the customer purchasing lifecycle.</p><ul><li><strong><code>Cart</code> &amp; <code>CartItem</code></strong>: Persistent shopping carts for users and guests.</li><li><strong><code>Order</code> &amp; <code>OrderItem</code></strong>: Immutable records of a completed checkout.</li><li><strong><code>OrderStatusHistory</code></strong>: Audit trail of state changes (Pending -&gt; Processing -&gt; Shipped).</li><li><strong><code>Invoice</code></strong>: Auto-generated billing documents.</li><li><strong><code>Return</code> &amp; <code>Refund</code></strong>: Workflows for handling RMA (Return Merchandise Authorization).</li></ul><h3 id="_3-inventory-logistics" tabindex="-1">3. Inventory &amp; Logistics <a class="header-anchor" href="#_3-inventory-logistics" aria-label="Permalink to &quot;3. Inventory &amp; Logistics&quot;">​</a></h3><p>Warehouse-level tracking and shipping calculations.</p><ul><li><strong><code>Warehouse</code></strong>: Physical locations.</li><li><strong><code>Inventory</code></strong>: Pivot tracking stock quantity per variant per warehouse.</li><li><strong><code>StockLog</code></strong>: Immutable ledger of all stock movements (adjustments, orders, returns) with <code>StockLogType</code> enums.</li><li><strong><code>ShippingZone</code>, <code>ShippingMethod</code>, <code>ShippingRate</code></strong>: Geographic delivery calculation engines.</li><li><strong><code>Shipment</code> &amp; <code>ShipmentTracking</code></strong>: Carrier integrations and delivery tracking events.</li></ul><h3 id="_4-users-authentication" tabindex="-1">4. Users &amp; Authentication <a class="header-anchor" href="#_4-users-authentication" aria-label="Permalink to &quot;4. Users &amp; Authentication&quot;">​</a></h3><ul><li><strong><code>User</code></strong>: Core authentication model.</li><li><strong><code>UserProfile</code> &amp; <code>Address</code></strong>: Customer details and multiple saved addresses (shipping/billing).</li><li><strong><code>CustomerGroup</code></strong>: Segmentation for bulk discounts or special pricing.</li><li><strong><code>PaymentMethod</code></strong>: Tokenized cards (via Stripe) saved for future use.</li></ul><h3 id="_5-marketing-promotions" tabindex="-1">5. Marketing &amp; Promotions <a class="header-anchor" href="#_5-marketing-promotions" aria-label="Permalink to &quot;5. Marketing &amp; Promotions&quot;">​</a></h3><p>A comprehensive suite for driving sales.</p><ul><li><strong><code>Coupon</code></strong>: Configurable discount codes (<code>CouponType</code>: Fixed, Percentage, Free Shipping, BOGO).</li><li><strong><code>Promotion</code></strong>: Automatic cart-level discounts based on rules.</li><li><strong><code>FlashSale</code> &amp; <code>FlashSaleItem</code></strong>: Time-limited urgency campaigns.</li><li><strong><code>Bundle</code> &amp; <code>BundleItem</code></strong>: Grouped products sold at a combined discount.</li><li><strong><code>PriceTier</code></strong>: Volume-based discounts (e.g., buy 10+, get 15% off).</li></ul><h3 id="_6-loyalty-affiliates" tabindex="-1">6. Loyalty &amp; Affiliates <a class="header-anchor" href="#_6-loyalty-affiliates" aria-label="Permalink to &quot;6. Loyalty &amp; Affiliates&quot;">​</a></h3><p>Customer retention mechanics.</p><ul><li><strong><code>LoyaltyPoint</code> &amp; <code>LoyaltyTransaction</code></strong>: Earn/redeem points system.</li><li><strong><code>Affiliate</code> &amp; <code>AffiliateConversion</code></strong>: Referral tracking and commission management.</li><li><strong><code>GiftCard</code> &amp; <code>GiftCardUsage</code></strong>: Digital balance cards.</li><li><strong><code>Wallet</code> &amp; <code>WalletTransaction</code></strong>: Internal store credit system.</li></ul><hr><h2 id="design-patterns" tabindex="-1">Design Patterns <a class="header-anchor" href="#design-patterns" aria-label="Permalink to &quot;Design Patterns&quot;">​</a></h2><h3 id="services-layer" tabindex="-1">Services Layer <a class="header-anchor" href="#services-layer" aria-label="Permalink to &quot;Services Layer&quot;">​</a></h3><p>Controllers are kept extremely thin. All business logic (e.g., the complex checkout process, stock deduction, payment intent creation) is delegated to dedicated classes in <code>app/Services/</code> (e.g., <code>OrderService</code>, <code>PaymentService</code>, <code>ProductService</code>).</p><h3 id="type-safety-enums" tabindex="-1">Type Safety (Enums) <a class="header-anchor" href="#type-safety-enums" aria-label="Permalink to &quot;Type Safety (Enums)&quot;">​</a></h3><p>LaraCommerce heavily utilizes PHP 8.1+ Enums in <code>app/Enums/</code> to guarantee type safety for statuses across the database and application logic. Examples include <code>OrderStatus</code>, <code>PaymentStatus</code>, and <code>ShipmentStatus</code>.</p><h3 id="traits" tabindex="-1">Traits <a class="header-anchor" href="#traits" aria-label="Permalink to &quot;Traits&quot;">​</a></h3><p>Reusable behaviors are abstracted into traits:</p><ul><li><code>HasSlug</code>: Auto-generates unique, SEO-friendly URLs.</li><li><code>Filterable</code>: Standardizes dynamic API query filtering (e.g., <code>?category=1&amp;min_price=100</code>).</li><li><code>ValidatesOnSave</code>: Intercepts Eloquent <code>saving</code> events to ensure model integrity.</li></ul><h3 id="api-resources" tabindex="-1">API Resources <a class="header-anchor" href="#api-resources" aria-label="Permalink to &quot;API Resources&quot;">​</a></h3><p>All API responses use Laravel API Resources (<code>app/Http/Resources/</code>) to strictly control JSON output, hide sensitive fields (like <code>cost_price</code> or internal IDs), and format dates/currencies consistently.</p>',33)])])}const m=o(i,[["render",s]]);export{g as __pageData,m as default};
